    function addTierRow(t={from:0,to:50,rate:0}){ $('#targetTierBody')?.insertAdjacentHTML('beforeend',`<tr><td><input class="form-control form-control-sm tier-from" type="number" value="${t.from}"></td><td><input class="form-control form-control-sm tier-to" type="number" value="${t.to}"></td><td><input class="form-control form-control-sm tier-rate" type="number" step="0.1" value="${t.rate}"></td><td><button class="btn btn-sm btn-soft text-danger" data-remove-tier>Remove</button></td></tr>`); }
    function openTargetModal(salesmanId){ const month=getVal('targetMonth')||monthNow(); const t=targetFor(salesmanId,month)||{id:'',salesmanId,month,targetAmount:50000,targetInvoices:100,commissionTiers:[{from:0,to:50,rate:0},{from:50,to:75,rate:2},{from:75,to:100,rate:3.5},{from:100,to:999,rate:5}],bonusOnTarget:500,notes:''}; refreshSalesmanSelect(); setVal('targetId',t.id||''); setVal('targetSalesman',t.salesmanId); setVal('targetMonthInput',t.month); setVal('targetAmount',t.targetAmount); setVal('targetInvoices',t.targetInvoices); setVal('bonusOnTarget',t.bonusOnTarget); setVal('targetNotes',t.notes||''); if($('#targetTierBody')) $('#targetTierBody').innerHTML=''; (t.commissionTiers||[]).forEach(addTierRow); showModal('#targetModal'); }
    function printPayoutSlipById(id){ const p=(db().commissionPayouts||[]).find(x=>x.id===id); if(!p) return; const html=`<div class="invoice-sheet" style="max-width:720px;margin:20px auto;padding:28px"><h2>Axtor POS Cloud</h2><p>Commission Payout Slip</p><hr><table class="table"><tr><th>Salesman</th><td>${salesmanName(p.salesmanId)}</td></tr><tr><th>Month</th><td>${p.month}</td></tr><tr><th>Sales</th><td>${money(p.grossSales)}</td></tr><tr><th>Achievement</th><td>${Number(p.achievementPct||0).toFixed(1)}%</td></tr><tr><th>Commission</th><td>${money(p.commissionAmount)}</td></tr><tr><th>Bonus</th><td>${money(p.bonusAmount)}</td></tr><tr><th>Total Payout</th><td><strong>${money(p.totalPayout)}</strong></td></tr><tr><th>Status</th><td>${p.status}</td></tr></table><div style="margin-top:60px;border-top:1px solid #999;width:240px;padding-top:8px">Authorized Signature</div></div>`; openPrint(html); }
    function openSalesmanHistory(salesmanId){ const sm=salesmanById(salesmanId); if(!sm) return; if($('#historyModalName')) $('#historyModalName').textContent=sm.name; const months=[]; const nowDate=new Date(); for(let i=11;i>=0;i--){ const d=new Date(nowDate.getFullYear(),nowDate.getMonth()-i,1); months.push(d.toISOString().slice(0,7)); } const data=db(); const rows=months.map(m=>{ const t=targetFor(salesmanId,m)||{salesmanId,month:m,targetAmount:0,commissionTiers:[],bonusOnTarget:0}; const c=calcCommission(t); const payout=(data.commissionPayouts||[]).find(p=>p.salesmanId===salesmanId&&p.month===m); return {month:m,target:t.targetAmount||0,...c,status:payout?.status||'none'}; }); const paid=rows.filter(r=>r.total>0); const best=paid.length?paid.reduce((a,b)=>b.total>a.total?b:a):null; const worst=paid.length?paid.reduce((a,b)=>b.total<a.total?b:a):null; const avg=paid.length?paid.reduce((s,r)=>s+r.total,0)/paid.length:0; const totalYear=rows.reduce((s,r)=>s+r.total,0); if($('#historyStats')) $('#historyStats').innerHTML=`<div class="col-md-3"><div class="mini-stat"><span>Best Month</span><h5>${best?best.month:'—'}</h5><small>${best?money(best.total):''}</small></div></div><div class="col-md-3"><div class="mini-stat"><span>Avg Monthly Commission</span><h5>${money(avg)}</h5></div></div><div class="col-md-3"><div class="mini-stat"><span>Total Earned (12 Months)</span><h5>${money(totalYear)}</h5></div></div><div class="col-md-3"><div class="mini-stat"><span>Lowest Month</span><h5>${worst?worst.month:'—'}</h5><small>${worst?money(worst.total):''}</small></div></div>`; if($('#historyTableBody')) $('#historyTableBody').innerHTML=rows.map(r=>`<tr><td>${r.month}</td><td>${money(r.target)}</td><td>${money(r.actualSales)}</td><td>${r.achievementPct.toFixed(1)}%</td><td>${money(r.commission)}</td><td>${money(r.bonus)}</td><td class="fw-bold">${money(r.total)}</td><td>${r.status==='none'?badge('—','draft'):badge(r.status,r.status==='paid'?'paid':'pending')}</td></tr>`).join(''); const canvas=$('#salesmanHistoryChart'); if(canvas&&window.Chart){ if(window.salesmanHistoryChartInstance && typeof window.salesmanHistoryChartInstance.destroy==='function') window.salesmanHistoryChartInstance.destroy(); window.salesmanHistoryChartInstance=new Chart(canvas,{type:'line',data:{labels:months,datasets:[{label:'Commission Earned',data:rows.map(r=>r.commission),borderColor:'#0f9f78',backgroundColor:'rgba(15,159,120,0.15)',tension:.4,fill:true,pointBackgroundColor:'#0f9f78'},{label:'Bonus',data:rows.map(r=>r.bonus),borderColor:'#f59e0b',backgroundColor:'rgba(245,158,11,0.10)',tension:.4,fill:false}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom'}},scales:{y:{beginAtZero:true,ticks:{callback:v=>'QAR '+v.toLocaleString()}}}}}); } showModal('#salesmanHistoryModal'); }
    function initSalesmanSelfView(){ const u=selfUser(); if(!u) return; document.querySelectorAll('.nav-tabs .nav-item').forEach(li=>{ const btn=li.querySelector('[data-bs-target]'); if(btn && btn.dataset.bsTarget!=='#performance') li.style.display='none'; }); document.querySelector('[data-bs-target="#performance"]')?.click(); const titleEl=document.querySelector('.page-title h2'); if(titleEl) titleEl.textContent='My Performance'; toast(`Welcome back, ${u.name}! Here's your commission summary.`); }

