    $('#addTierBtn')?.addEventListener('click',()=>addTierRow({from:0,to:999,rate:0}));
    $('#copyTargetsNextMonthBtn')?.addEventListener('click',()=>{ const currentMonth=getVal('targetMonth')||monthNow(); const [y,m]=currentMonth.split('-').map(Number); const nextMonth=new Date(y,m,1).toISOString().slice(0,7); const data=db(); data.salesmanTargets=data.salesmanTargets||[]; let copied=0,skipped=0; filteredSalesmen().forEach(s=>{ const existing=targetFor(s.id,currentMonth); if(!existing) return; if(data.salesmanTargets.some(t=>t.salesmanId===s.id&&t.month===nextMonth)){ skipped++; return; } data.salesmanTargets.push({...clone(existing),id:nextNo('TGT',data.salesmanTargets),month:nextMonth}); copied++; }); if(copied===0&&skipped===0){ toast('No targets found for this month to copy.','warning'); return; } save(data); audit(`Copied ${copied} targets from ${currentMonth} to ${nextMonth}`,'Targets','Copied'); toast(`${copied} target(s) copied to ${nextMonth}${skipped?`. ${skipped} already existed and were skipped.`:'.'}`); setVal('targetMonth',nextMonth); renderAll(); });
    document.addEventListener('click',e=>{ const addSm=e.target.closest('[data-add-salesman]'); if(addSm){ setVal('editSalesmanId',''); ['salesmanName','salesmanPhone','salesmanEmail','salesmanBranch','salesmanJoinDate'].forEach(id=>setVal(id,'')); const title=document.querySelector('#addSalesmanModal .modal-title'); if(title) title.textContent='Add Salesman'; } const rem=e.target.closest('[data-remove-tier]'); if(rem){ rem.closest('tr')?.remove(); return; } const edit=e.target.closest('[data-edit-salesman]'); if(edit){ const sm=salesmanById(edit.dataset.editSalesman); if(!sm) return; setVal('editSalesmanId',sm.id); setVal('salesmanName',sm.name); setVal('salesmanPhone',sm.phone||''); setVal('salesmanEmail',sm.email||''); setVal('salesmanBranch',sm.branch||'Main Branch'); setVal('salesmanJoinDate',sm.joinDate||''); const title=document.querySelector('#addSalesmanModal .modal-title'); if(title) title.textContent='Edit Salesman'; showModal('#addSalesmanModal'); return; } const tog=e.target.closest('[data-toggle-salesman]'); if(tog){ const data=db(); const sm=data.salesmen.find(s=>s.id===tog.dataset.toggleSalesman); if(!sm) return; sm.active=sm.active===false?true:false; save(data); audit(`Salesman ${sm.active?'activated':'deactivated'}: ${sm.name}`,'Salesmen',sm.active?'Active':'Inactive'); toast(`${sm.name} has been ${sm.active?'activated':'deactivated'}`); populateTerminalSalesmen(); populateNewSaleSalesmanDropdown(); renderAll(); return; } const set=e.target.closest('[data-set-target]'); if(set){ openTargetModal(set.dataset.setTarget); return; } const view=e.target.closest('[data-view-performance]'); if(view){ openSalesmanHistory(view.dataset.viewPerformance); return; } const ap=e.target.closest('[data-approve-payout]'); if(ap){ if(!['Owner','Manager'].includes(currentUserRole())){ toast('Only Owner/Manager can approve commission','danger'); return; } const data=db(); const p=data.commissionPayouts.find(x=>x.id===ap.dataset.approvePayout); if(p){ p.status='approved'; p.approvedBy=currentUserRole(); save(data); audit(`Commission approved for ${salesmanName(p.salesmanId)} — ${money(p.totalPayout)}`,'Pending','Approved'); toast('Commission approved'); renderPayouts(); } return; } const paid=e.target.closest('[data-paid-payout]'); if(paid){ const checkData=db(); const checkP=checkData.commissionPayouts.find(x=>x.id===paid.dataset.paidPayout); if(!checkP) return; if(checkP.status==='pending'){ toast('Commission must be approved by Owner/Manager before marking as paid.','danger'); return; } if(checkP.status==='paid'){ toast('This commission is already marked as paid.','warning'); return; } setVal('payoutIndex',paid.dataset.paidPayout); setVal('payoutPaidDate',new Date().toISOString().slice(0,10)); showModal('#paidPayoutModal'); return; } const pr=e.target.closest('[data-print-payout]'); if(pr){ printPayoutSlipById(pr.dataset.printPayout); return; } const wa=e.target.closest('[data-whatsapp-payout]'); if(wa){ const p=db().commissionPayouts.find(x=>x.id===wa.dataset.whatsappPayout); if(!p) return; const sm=salesmanById(p.salesmanId); const phone=(sm?.phone||'').replace(/\D/g,''); if(!phone){ toast('No phone number on file for this salesman.','warning'); return; } const msg=[`*Axtor POS Cloud — Commission Slip*`,'',`Dear *${sm.name}*,`,`Your commission for *${p.month}* has been processed.`,'',`📊 Sales Achieved: *${money(p.grossSales)}*`,`🎯 Achievement: *${Number(p.achievementPct||0).toFixed(1)}%*`,`💰 Commission (${p.commissionRate}%): *${money(p.commissionAmount)}*`,`🎁 Bonus: *${money(p.bonusAmount)}*`,`✅ Total Payout: *${money(p.totalPayout)}*`,'',`Payment Method: ${p.paymentMethod||'N/A'}`,`Paid Date: ${p.paidDate||'N/A'}`,'','Thank you for your hard work this month!'].join('\n'); navigator.clipboard?.writeText(msg).catch(()=>{}); window.open('https://wa.me/'+phone+'?text='+encodeURIComponent(msg),'_blank'); toast('Opening WhatsApp with commission slip...'); return; } const disp=e.target.closest('[data-dispute-payout]'); if(disp){ setVal('disputePayoutId',disp.dataset.disputePayout); setVal('disputeReason',''); showModal('#disputePayoutModal'); return; } });
    $('#saveSalesmanBtn')?.addEventListener('click',()=>{ const data=db(); data.salesmen=data.salesmen||[]; const editId=getVal('editSalesmanId'); if(editId){ const sm=data.salesmen.find(s=>s.id===editId); if(sm){ sm.name=getVal('salesmanName'); sm.phone=getVal('salesmanPhone'); sm.email=getVal('salesmanEmail'); sm.branch=getVal('salesmanBranch')||'Main Branch'; sm.joinDate=getVal('salesmanJoinDate'); save(data); audit(`Salesman updated: ${sm.name}`,'Salesmen','Updated'); toast('Salesman updated'); } } else { const existingNums=(data.salesmen||[]).map(s=>parseInt((s.id||'').replace('SM',''))||0); const nextNum=existingNums.length>0?Math.max(...existingNums)+1:1; const id='SM'+String(nextNum).padStart(3,'0'); data.salesmen.push({id,name:getVal('salesmanName'),phone:getVal('salesmanPhone'),email:getVal('salesmanEmail'),branch:getVal('salesmanBranch')||'Main Branch',active:true,joinDate:getVal('salesmanJoinDate')||new Date().toISOString().slice(0,10)}); save(data); audit(`Salesman added: ${getVal('salesmanName')}`,'Salesmen','Added'); toast('Salesman added'); } setVal('editSalesmanId',''); const title=document.querySelector('#addSalesmanModal .modal-title'); if(title) title.textContent='Add Salesman'; hideModal('#addSalesmanModal'); populateTerminalSalesmen(); populateNewSaleSalesmanDropdown(); renderAll(); });
    $('#saveTargetBtn')?.addEventListener('click',()=>{ const data=db(); data.salesmanTargets=data.salesmanTargets||[]; const id=getVal('targetId'); const tiers=$$('#targetTierBody tr').map(r=>({from:num($('.tier-from',r).value),to:num($('.tier-to',r).value),rate:num($('.tier-rate',r).value)})); const rec={id:id||nextNo('TGT',data.salesmanTargets),salesmanId:getVal('targetSalesman'),month:getVal('targetMonthInput'),targetAmount:num(getVal('targetAmount')),targetInvoices:num(getVal('targetInvoices')),commissionTiers:tiers,bonusOnTarget:num(getVal('bonusOnTarget')),notes:getVal('targetNotes')}; const i=data.salesmanTargets.findIndex(t=>t.id===rec.id || (t.salesmanId===rec.salesmanId && t.month===rec.month)); if(i>=0) data.salesmanTargets[i]=rec; else data.salesmanTargets.push(rec); save(data); audit(`Target saved for ${salesmanName(rec.salesmanId)} — ${rec.month}`,'Target','Saved'); toast('Target saved'); hideModal('#targetModal'); renderAll(); });
    $('#confirmPaidBtn')?.addEventListener('click',()=>{ const data=db(); const p=data.commissionPayouts.find(x=>x.id===getVal('payoutIndex')); if(p){ p.status='paid'; p.paidDate=getVal('payoutPaidDate'); p.paymentMethod=getVal('payoutMethod'); p.notes=getVal('payoutNotes'); save(data); audit(`Commission marked paid for ${salesmanName(p.salesmanId)} — ${money(p.totalPayout)}`,'Approved','Paid'); toast('Commission marked as paid ✓'); hideModal('#paidPayoutModal'); renderPayouts(); } });
    $('#submitDisputeBtn')?.addEventListener('click',()=>{ const reason=getVal('disputeReason').trim(); if(!reason){ toast('Please enter a dispute reason.','warning'); return; } const data=db(); const p=(data.commissionPayouts||[]).find(x=>x.id===getVal('disputePayoutId')); if(!p) return; const sm=salesmanById(p.salesmanId); data.approvalRequests=data.approvalRequests||[]; data.approvalRequests.unshift({id:nextNo('APR',data.approvalRequests),type:'Commission Dispute',detail:`${sm?.name||p.salesmanId} (${p.month}): ${reason}`,amount:p.totalPayout,status:'Pending'}); p.disputed=true; p.disputeReason=reason; save(data); audit(`Commission dispute raised for ${sm?.name} — ${p.month}`,'Pending','Disputed'); toast('Dispute submitted. Owner will be notified in Approvals.'); hideModal('#disputePayoutModal'); renderPayouts(); });
